const query = $input.first().json.query || {};
const project_id = query.project_id || '';
const action = query.action || 'unknown';

return [{ json: { project_id, action } }];

const result = $input.first().json.result;
const parsed = typeof result === 'string' ? JSON.parse(result) : result;
const projectId = $('Parse Query Params').first().json.project_id;

if (!parsed || !parsed.success || !parsed.suggestions || parsed.suggestions.length === 0) {
  return [{ json: { text: '⚠️ Keine offenen Materialien zum Bestellen.', projectId, ordersCreated: 0 } }];
}

// For now, we don't auto-create POs. Just mark them as ready.
// The actual PO creation needs supplier grouping which requires more logic.
const suggestions = parsed.suggestions;
let totalItems = 0;
let totalValue = 0;

let lines = [];
lines.push('✅ <b>Bestellung genehmigt!</b>');
lines.push('');

for (const s of suggestions) {
  lines.push(`<b>${s.trade}</b>: ${s.item_count} Materialien`);
  totalItems += Number(s.item_count);
  totalValue += Number(s.est_total_value || 0);
}

lines.push('');
lines.push(`Gesamt: ${totalItems} Materialien (~€${totalValue.toFixed(0)})`);
lines.push('');
lines.push('Bestellungen können jetzt in der App erstellt werden.');

return [{ json: { text: lines.join('\n'), projectId, ordersCreated: 0, totalItems, totalValue } }];

